"""Set the global config and logger."""

from __future__ import annotations

import logging
from collections.abc import Generator
from contextlib import contextmanager
from typing import Any

from .cli_colors import parse_cli_ctx
from .logger_utils import make_logger
from .utils import ManimConfig, ManimFrame, make_config_parser

__all__ = [
    "logger",
    "console",
    "error_console",
    "config",
    "frame",
    "tempconfig",
    "cli_ctx_settings",
]

parser = make_config_parser()

# Logger usage: accessible globally as `manim.logger` or via `logging.getLogger("manim")`.
# For printing, use `manim.console.print()` instead of the built-in `print()`.
# For error output, use `error_console`, which prints to stderr.
logger, console, error_console = make_logger(
    parser["logger"],
    parser["CLI"]["verbosity"],
)
cli_ctx_settings = parse_cli_ctx(parser["CLI_CTX"])
# TODO: temporary to have a clean terminal output when working with PIL or matplotlib
logging.getLogger("PIL").setLevel(logging.INFO)
logging.getLogger("matplotlib").setLevel(logging.INFO)

config = ManimConfig().digest_parser(parser)
# TODO: to be used in the future - see PR #620
# https://github.com/ManimCommunity/manim/pull/620
frame = ManimFrame(config)

# ── iOS defaults ───────────────────────────────────────────────────
# Manim's animation cache hashes every mobject in scene.mobjects on
# every play() by JSON-serializing the whole tree. For scenes with
# accumulated MathTex (each character is a VMobject with hundreds of
# bezier points), the serialized JSON + the _Memoizer's _already_processed
# set grow to gigabytes. Desktop has swap to absorb this; iOS has a
# hard 16 GB jetsam limit and is killed around animation 18–25.
#
# Manim itself warns about this at 170 k sub-mobjects and suggests
# `--disable_caching`. On iOS we always disable it by default because
# LaTeX-heavy scenes almost always cross that threshold, and saving
# a potentially-cached partial movie file matters less than not
# getting killed. Users can still re-enable with
#   from manim import config; config.disable_caching = False
import sys as _ios_sys
if _ios_sys.platform.startswith("ios"):
    try:
        config.disable_caching = True
    except Exception:
        pass
    # iOS has no increased-memory-limit entitlement on personal dev
    # teams, so jetsam caps the process at ~50 % of device RAM
    # (≈ 8 GB on a 16 GB iPad). 1920×1080 RGBA frames are 8 MB each;
    # between the queued frames, camera pixel_array, static_image,
    # and encoder ref frames, the pipeline alone reserves hundreds of
    # MB per active animation — before user-code mobjects.
    # Drop the default render resolution to 720p, which is 4× less
    # memory per frame end-to-end. Still looks fine on iPad screens
    # (native is ~1668×2388 but 720p reads crisp at playback size).
    # Users can override with `with tempconfig({"pixel_width": 1920, ...})`.
    try:
        config.pixel_height = 720
        config.pixel_width = 1280
        # 30 fps instead of 60 → half the total frames, half the
        # per-animation allocation peak.
        config.frame_rate = 30
    except Exception:
        pass
    # Switch tqdm progress bars from "display" (leave=False, bar is
    # erased on close) to "leave" (bar stays in scrollback). Inside
    # our SwiftTerm-backed PTY, "display" mode makes each finished
    # animation flash a bar then clear it — the user can't tell which
    # animations ran. "leave" keeps one bar line per animation so
    # the scrollback reads like a proper render log.
    try:
        config.progress_bar = "leave"
    except Exception:
        pass

    # Enable partial-movie-file flushing between scenes so the disk
    # cache doesn't grow either. (Disk isn't the killer — RAM is —
    # but long TSNE-style scenes write 100+ partial .mp4 files,
    # which also reference-keep internal FFmpeg/PyAV objects from
    # `combine_files` when they get concatenated.)
    try:
        config.flush_cache = True
    except Exception:
        pass

    # Tighten CPython's generational GC thresholds. Default is
    # (700, 10, 10) — gen-0 collects every 700 new allocations,
    # gen-1 every 10 gen-0 collections, gen-2 every 10 gen-1 collections.
    # On an 8 GB jetsam budget, a manim scene that creates ~30k
    # allocations per animation can pile up 10× that before gen-2
    # runs, which is where reference cycles (VMobject parents holding
    # submobjects holding a reference to their parent, Animation
    # holding mobject + starting_mobject + target_mobject, etc.) get
    # reaped. Drop thresholds so gen-2 runs roughly once per animation.
    try:
        import gc as _ios_gc
        _ios_gc.set_threshold(200, 5, 5)
        # Also enable DEBUG_STATS? No — just leave stats off in prod.
    except Exception:
        pass


# This has to go here because it needs access to this module's config
@contextmanager
def tempconfig(temp: ManimConfig | dict[str, Any]) -> Generator[None, None, None]:
    """Temporarily modifies the global ``config`` object using a context manager.

    Inside the ``with`` statement, the modified config will be used.  After
    context manager exits, the config will be restored to its original state.

    Parameters
    ----------
    temp
        Object whose keys will be used to temporarily update the global
        ``config``.

    Examples
    --------

    Use ``with tempconfig({...})`` to temporarily change the default values of
    certain config options.

    .. code-block:: pycon

       >>> config["frame_height"]
       8.0
       >>> with tempconfig({"frame_height": 100.0}):
       ...     print(config["frame_height"])
       100.0
       >>> config["frame_height"]
       8.0

    """
    global config
    original = config.copy()

    temp = {k: v for k, v in temp.items() if k in original}

    # In order to change the config that every module has access to, use
    # update(), DO NOT use assignment.  Assigning config = some_dict will just
    # make the local variable named config point to a new dictionary, it will
    # NOT change the dictionary that every module has a reference to.
    config.update(temp)
    try:
        yield
    finally:
        config.update(original)  # update, not assignment!
